import { Component, Prop, h, Element, Event, EventEmitter, Watch, State } from '@stencil/core';
import { customTwMerge, propagateToSlot } from '../../utils/utils';

@Component({ tag: 'wdpr-button-dock', shadow: true })
export class WdprButtonDock {
  @Element() el!: HTMLWdprButtonDockElement;

  /**
   * @internal
   * State to detect content in slot total
   */
  @State() private hasTotal = false;

  /** The label that will be displayed
   * @type {string}
   */
  @Prop({ reflect: true }) label?: string;

  /** The sublabel that will be displayed
   * @type {string}
   */
  @Prop({ reflect: true }) subLabel?: string;

  /** The centered label that will be displayed
   * @type {string}
   */
  @Prop({ reflect: true }) centeredLabel?: string;

  /** Accessible name for the region container
   * @default 'Actions'
   * @type {string}
   */
  @Prop({ attribute: 'a11y-label' }) a11yLabel: string = 'Actions';
  @Prop({ reflect: true }) showDivider = true;

  /**
   * Visually dim + sets aria-disabled on the container
   * @default false
   * @type {boolean}
   */
  @Prop({ reflect: true }) disabled = false;
  @Watch('disabled') handleDisabledChange(next: boolean) {
    this.disabledChanged.emit(next);
    // Propagate to slotted content
    this.syncButtonBarSlot();
  }

  /** Event emitted when disabled changes
   * @event
   * @type {boolean}
   */
  @Event({ eventName: 'disabledChanged' }) disabledChanged!: EventEmitter<boolean>;

  componentDidLoad() {
    this.syncButtonBarSlot();
  }

  private get headerAndTotalRowWrapperClasses() {
    const hasHeader = !!this.label || !!this.subLabel;
    // Bitmask:
    // 1 (01) → hasHeader
    // 2 (10) → hasTotal
    const mask = (hasHeader ? 1 : 0) | (this.hasTotal ? 2 : 0);

    const justifyClass: Record<number, string | null> = {
      0: 'hidden',          // 00 → neither header nor total
      1: 'justify-start',   // 01 → only header
      2: 'justify-end',     // 10 → only total
      3: 'justify-between', // 11 → both header and total
    };

    return customTwMerge(headerAndTotalRowWrapperBaseClasses, justifyClass[mask]);
  }

  private syncButtonBarSlot() {
    const slotEl = this.el.shadowRoot?.querySelector(`slot[name="button-bar"]`) as HTMLSlotElement | null;

    // Propagate "disabled" to assigned elements, falling back to aria-disabled
    propagateToSlot(slotEl, 'disabled', this.disabled, 'wdpr-button-bar');
  }

  private onTotalSlotChange = () => {
    const sr = this.el.shadowRoot!;
    const total = sr.querySelector('slot[name="total"]') as HTMLSlotElement;
    this.hasTotal = !!total?.assignedNodes({ flatten: true }).length;
  };

  private onButtonBarSlotChange = () => {
    const buttonBar = this.el.shadowRoot?.querySelector('slot[name="button-bar"]') as HTMLSlotElement;
    propagateToSlot(buttonBar!, 'disabled', this.disabled, 'wdpr-button-bar');
  };

  private renderHeaderAndTotalRow() {
    return (
      <div class={this.headerAndTotalRowWrapperClasses}>
        <div class="flex flex-col items-start gap-025">
          <h2 class="heading-small text-text-heading">{this.label}</h2>
          <p class="body-small text-text-disclaimer">{this.subLabel}</p>
        </div>

        <slot name="total" onSlotchange={this.onTotalSlotChange} />
      </div>
    );
  }

  render() {
    return (
      <div class="w-full">
        {this.showDivider && <wdpr-divider part="divider" />}
        <section role="region" aria-label={this.a11yLabel} aria-disabled={this.disabled ? 'true' : 'false'} class={containerClasses}>
          {this.renderHeaderAndTotalRow()}

          {this.centeredLabel && (
            <div class="pr-200 pl-200 w-full flex justify-center">
              <p class="heading-xsmall">{this.centeredLabel}</p>
            </div>
          )}

          <section class={buttonBarFrameClasses} part="button-bar-frame">
            <slot name="button-bar" onSlotchange={this.onButtonBarSlotChange} />
          </section>
        </section>
      </div>
    );
  }
}

const containerClasses = 'flex flex-col items-center gap-200 bg-surface-default w-full p-300';
const headerAndTotalRowWrapperBaseClasses = 'flex items-center self-stretch';
const buttonBarFrameClasses = 'w-full items-center self-stretch gap-200';
