import { Component, Element, h, Host, Prop, State, Watch } from '@stencil/core';
import { propagateToSlot } from '../../utils/utils';

export type ButtonBarLayout = 'fill' | 'split' | 'stacked' | 'hug';

type ButtonSlotName = 'primary-button' | 'secondary-button' | 'tertiary-button';

const SLOT_SELECTORS: Record<ButtonSlotName, string> = {
  'primary-button': 'slot[name="primary-button"]',
  'secondary-button': 'slot[name="secondary-button"]',
  'tertiary-button': 'slot[name="tertiary-button"]',
};

@Component({
  tag: 'wdpr-button-bar',
  shadow: true,
})
export class WdprButtonBar {
  /**
   * Reference to host element.
   */
  @Element() el!: HTMLWdprButtonBarElement;

  @State() _hasPrimary = false;

  @State() _hasSecondary = false;

  @State() _hasTertiary = false;

  /**
   * Disables all slotted buttons in the bar.
   * @default false
   */
  @Prop({ reflect: true }) disabled = false;

  /**
   * Layout mode:
   * - 'split'  : two or three columns (buttons distributed evenly)
   * - 'stacked': always one column (buttons stacked vertically)
   * - 'hug'    : compact layout for one or two buttons
   * - 'fill'   : buttons stretch to fill the available space
   * @default 'split'
   */
  @Prop({ reflect: true }) layout: ButtonBarLayout = 'split';

  /**
   * When true, buttons stack vertically on mobile viewports for fill, split,
   * and hug layouts. When false, buttons remain side-by-side at all widths.
   * Has no effect on the stacked layout.
   * @default true
   */
  @Prop({ reflect: true }) autoStack = true;

  @Watch('disabled')
  _handleDisabledChange(): void {
    this._syncAllSlots();
  }

  @Watch('layout')
  _handleLayoutChange(): void {
    this._syncAllSlots();
  }

  // ---------- lifecycle ----------

  public componentDidLoad(): void {
    this._handlePrimarySlotChange();
    this._handleSecondarySlotChange();
    this._handleTertiarySlotChange();
    this._syncAllSlots();
  }

  // ---------- slot helpers ----------

  private _getSlotEl(slotName: ButtonSlotName): HTMLSlotElement | null {
    return (this.el.shadowRoot?.querySelector(SLOT_SELECTORS[slotName]) as HTMLSlotElement | null) ?? null;
  }

  private _hasAssignedElements(slotEl: HTMLSlotElement | null): boolean {
    return !!slotEl && slotEl.assignedElements({ flatten: true }).length > 0;
  }

  private _syncSlot(slotName: ButtonSlotName): void {
    const slotEl = this._getSlotEl(slotName);

    // Propagate "disabled" to assigned elements, falling back to aria-disabled
    propagateToSlot(slotEl, 'disabled', this.disabled, 'wdpr-button');
  }

  private _syncAllSlots(): void {
    this._syncSlot('primary-button');
    this._syncSlot('secondary-button');
    this._syncSlot('tertiary-button');
  }

  // ---------- slot handlers ----------

  private _handlePrimarySlotChange = (): void => {
    const slotEl = this._getSlotEl('primary-button');
    this._hasPrimary = this._hasAssignedElements(slotEl);
    this._syncSlot('primary-button');
  };

  private _handleSecondarySlotChange = (): void => {
    const slotEl = this._getSlotEl('secondary-button');
    this._hasSecondary = this._hasAssignedElements(slotEl);
    this._syncSlot('secondary-button');
  };

  private _handleTertiarySlotChange = (): void => {
    const slotEl = this._getSlotEl('tertiary-button');
    this._hasTertiary = this._hasAssignedElements(slotEl);
    this._syncSlot('tertiary-button');
  };

  // ---------- layout classes ----------

  private get _containerClass(): string {
    const stack = this.autoStack ? 'flex-col sm:flex-row' : 'flex-row';
    switch (this.layout) {
      case 'split':
        return `flex ${stack} ${this._hasTertiary ? 'justify-between' : 'justify-around'} items-center gap-200 w-full`;
      case 'stacked':
        return `grid grid-cols-1 gap-200 w-full`;
      case 'hug':
        return `flex justify-end items-center gap-100 w-auto`;
      case 'fill':
        return `flex justify-between items-center w-full`;
      default:
        return '';
    }
  }

  private get _rightClass(): string {
    const stack = this.autoStack ? 'flex-col sm:flex-row' : 'flex-row';
    switch (this.layout) {
      case 'split': {
        const justify = this._hasTertiary || !this._hasSecondary ? 'justify-end' : 'justify-between';

        return `flex ${stack} ${justify} items-center gap-200 w-full`;
      }
      case 'stacked':
        return `grid grid-cols-1 gap-200 w-full`;
      case 'hug':
        return `flex ${this.autoStack ? 'flex-col sm:flex-row' : 'flex-row'} justify-end items-center gap-100 w-auto`;
      case 'fill':
        if (this._hasSecondary) {
          return this.autoStack
            ? `grid grid-cols-1 sm:grid-cols-2 gap-200 w-full`
            : `grid grid-cols-2 gap-200 w-full`;
        }

        return `grid grid-cols-1 gap-200 w-full`;
      default:
        return '';
    }
  }

  private get _primaryWrapClass(): string | undefined {
    switch (this.layout) {
      case 'split':
        return this._hasTertiary ? 'md:col-start-3' : 'md:col-start-2';
      case 'stacked':
      case 'hug':
      default:
        return undefined;
    }
  }

  private get _secondaryWrapClass(): string | undefined {
    if (!this._hasSecondary) {
      return 'hidden';
    }
    switch (this.layout) {
      case 'split':
        return 'md:col-start-1';
      case 'stacked':
      case 'hug':
      default:
        return undefined;
    }
  }

  private get _tertiaryWrapClass(): string | undefined {
    switch (this.layout) {
      case 'split':
        return this._hasTertiary ? 'md:col-start-2' : 'hidden';
      case 'hug':
        return 'hidden';
      case 'stacked':
      default:
        return undefined;
    }
  }

  // ---------- render ----------

  public render() {
    return (
      <Host role="group" aria-disabled={this.disabled ? 'true' : 'false'}>
        <div class={this._containerClass}>
          {this.layout === 'split' && (
            <div class={this._tertiaryWrapClass}>
              <slot name="tertiary-button" onSlotchange={this._handleTertiarySlotChange}></slot>
            </div>
          )}

          <div class={this._rightClass}>
            <div class={this._secondaryWrapClass}>
              <slot name="secondary-button" onSlotchange={this._handleSecondarySlotChange}></slot>
            </div>

            <div class={this._primaryWrapClass}>
              <slot name="primary-button" onSlotchange={this._handlePrimarySlotChange}></slot>
            </div>
          </div>
        </div>
      </Host>
    );
  }
}
